  background.addColorStop(0.5, "#11233a");
  background.addColorStop(1, "#1f5f5b");
  ctx.fillStyle = background;
  ctx.fillRect(0, 0, width, height);

  drawStarfield(ctx, state, width, height);
  drawFloorGrid(ctx, width, height);

